#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    static void solve(vector<int>& nums) {
        if (nums.empty()) {
            cout << "Error: trying to dequeue from an empty queue"
            return;
        }
        cout << nums.front() << endl;
        nums.erase(nums.begin());
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    Solution::solve(nums);
    return 0;
}
